import{_ as e,c as t,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Продвинутые функции: принципы форматирования | opencode-md-table-formatter","description":"Узнайте принципы форматирования в opencode-md-table-formatter. Освойте скрытый режим, спецификации таблиц и способы выравнивания, полностью понимая работу плагина.","frontmatter":{"title":"Продвинутые функции: принципы форматирования | opencode-md-table-formatter","subtitle":"Продвинутые функции: принципы форматирования","sidebarTitle":"Понимание принципов работы","order":2,"description":"Узнайте принципы форматирования в opencode-md-table-formatter. Освойте скрытый режим, спецификации таблиц и способы выравнивания, полностью понимая работу плагина.","prerequisite":["start-getting-started","start-features"],"tags":["продвинутые","принципы","спецификация"]},"headers":[],"relativePath":"ru/franlol/opencode-md-table-formatter/advanced/index.md","filePath":"ru/franlol/opencode-md-table-formatter/advanced/index.md"}'),l={name:"ru/franlol/opencode-md-table-formatter/advanced/index.md"};function i(n,a,s,d,c,h){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="продвинутые-функции-подробное-рассмотрение-технических-деталеи-форматирования-markdown-таблиц" tabindex="-1">Продвинутые функции: подробное рассмотрение технических деталей форматирования Markdown-таблиц <a class="header-anchor" href="#продвинутые-функции-подробное-рассмотрение-технических-деталеи-форматирования-markdown-таблиц" aria-label="Permalink to &quot;Продвинутые функции: подробное рассмотрение технических деталей форматирования Markdown-таблиц&quot;">​</a></h1><h2 id="обзор-главы" tabindex="-1">Обзор главы <a class="header-anchor" href="#обзор-главы" aria-label="Permalink to &quot;Обзор главы&quot;">​</a></h2><p>В этой главе подробно рассматриваются технические детали форматирования Markdown-таблиц, включая принципы работы скрытого режима OpenCode, структурные требования к эффективным таблицам и подробное описание способов выравнивания. Изучив эти материалы, вы полностью поймёте, как плагин обрабатывает форматирование таблиц, и как избежать распространённых ошибок.</p><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Рекомендуется изучать содержание этой главы в следующем порядке:</p><div class="info custom-block"><p class="custom-block-title">Путь обучения</p><ol><li><strong>Принципы скрытого режима</strong> → понять, почему нужна специальная обработка скрытого режима OpenCode</li><li><strong>Спецификация таблиц</strong> → освоить, какие таблицы могут быть правильно отформатированы</li><li><strong>Подробно о способах выравнивания</strong> → научиться управлять выравниванием и эстетикой таблиц</li></ol></div><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><p>Перед началом этой главы убедитесь, что вы уже:</p><ul><li>[x] Завершили <a href="./../../start/getting-started/">Быстрый старт</a>, успешно установили и настроили плагин</li><li>[x] Прочитали <a href="./../../start/features/">Обзор функций</a>, поняли базовые функции плагина</li></ul><div class="warning custom-block"><p class="custom-block-title">Важное замечание</p><p>Если вы ещё не завершили базовое обучение, рекомендуется вернуться к <a href="./../../start/getting-started/">Быстрый старт</a> и начать.</p></div><h2 id="навигация-по-урокам" tabindex="-1">Навигация по урокам <a class="header-anchor" href="#навигация-по-урокам" aria-label="Permalink to &quot;Навигация по урокам&quot;">​</a></h2><h3 id="принципы-скрытого-режима" tabindex="-1"><a href="./concealment-mode/">Принципы скрытого режима</a> <a class="header-anchor" href="#принципы-скрытого-режима" aria-label="Permalink to &quot;[Принципы скрытого режима](./concealment-mode/)&quot;">​</a></h3><p>Поймите принципы работы скрытого режима OpenCode и то, как плагин правильно вычисляет отображаемую ширину. Вы узнаете:</p><ul><li>Что такое скрытый режим и почему нужна специальная обработка</li><li>Как работает алгоритм удаления Markdown-символов</li><li>Роль <code>Bun.stringWidth()</code> в вычислении ширины</li></ul><p><strong>Предполагаемое время</strong>: 8 минут | <strong>Сложность</strong>: средняя | <strong>Предварительные условия</strong>: Обзор функций</p><hr><h3 id="спецификация-таблиц" tabindex="-1"><a href="./table-spec/">Спецификация таблиц</a> <a class="header-anchor" href="#спецификация-таблиц" aria-label="Permalink to &quot;[Спецификация таблиц](./table-spec/)&quot;">​</a></h3><p>Освойте структурные требования к эффективным Markdown-таблицам, чтобы избежать ошибок &quot;недопустимая таблица&quot;. Вы узнаете:</p><ul><li>Какая структура таблицы является допустимой</li><li>Роль разделительной строки и требования к её формату</li><li>Принципы проверки согласованности количества столбцов</li><li>Как быстро выявить проблемы структуры таблицы</li></ul><p><strong>Предполагаемое время</strong>: 6 минут | <strong>Сложность</strong>: начальная | <strong>Предварительные условия</strong>: Принципы скрытого режима</p><hr><h3 id="подробно-о-способах-выравнивания" tabindex="-1"><a href="./alignment/">Подробно о способах выравнивания</a> <a class="header-anchor" href="#подробно-о-способах-выравнивания" aria-label="Permalink to &quot;[Подробно о способах выравнивания](./alignment/)&quot;">​</a></h3><p>Освойте синтаксис и эффект трёх способов выравнивания, чтобы сделать таблицы более эстетичными. Вы узнаете:</p><ul><li>Синтаксис левого, центрального и правого выравнивания</li><li>Как указать способ выравнивания в разделительной строке</li><li>Алгоритм заполнения содержимого ячеек</li><li>Связь между выравниванием и отображаемой шириной</li></ul><p><strong>Предполагаемое время</strong>: 10 минут | <strong>Сложность</strong>: средняя | <strong>Предварительные условия</strong>: Спецификация таблиц</p><hr><h2 id="итог-главы" tabindex="-1">Итог главы <a class="header-anchor" href="#итог-главы" aria-label="Permalink to &quot;Итог главы&quot;">​</a></h2><p>После завершения этой главы вы:</p><ul><li>✅ Поймёте принципы работы скрытого режима OpenCode</li><li>✅ Освоите структурные требования к эффективным таблицам</li><li>✅ Сможете выявлять и исправлять недопустимые таблицы</li><li>✅ Уверенно используете три способа выравнивания</li><li>✅ Поймёте технические детали реализации плагина</li></ul><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этой главы вы можете:</p><ol><li><strong>Решать практические проблемы</strong> → изучить <a href="./../../faq/troubleshooting/">Частые вопросы</a>, чтобы быстро выявлять и решать проблемы</li><li><strong>Понять технические границы</strong> → прочитать <a href="./../../appendix/limitations/">Известные ограничения</a>, чтобы понять сценарии применения плагина</li><li><strong>Углубиться в реализацию</strong> → посмотреть <a href="./../../appendix/tech-details/">Технические детали</a>, чтобы понять механизм кэширования и оптимизацию производительности</li></ol><hr><div class="tip custom-block"><p class="custom-block-title">Практический совет</p><p>Если вы хотите быстро решить проблемы форматирования таблиц, сначала прочитайте <a href="./table-spec/">Спецификацию таблиц</a> этой главы — она содержит наиболее распространённые примеры недопустимых таблиц.</p></div>',34)])])}const m=e(l,[["render",i]]);export{u as __pageData,m as default};
